43	static void exec_once(Decode *s, vaddr_t pc) {
44	  s->pc = pc;
45	  s->snpc = pc;
46	  isa_exec_once(s);
47	  cpu.pc = s->dnpc;
48	#ifdef CONFIG_ITRACE
49	  char *p = s->logbuf;
50	  p += snprintf(p, sizeof(s->logbuf), FMT_WORD ":", s->pc);
51	  int ilen = s->snpc - s->pc;
52	  int i;
53	  uint8_t *inst = (uint8_t *)&s->isa.inst;
54	#ifdef CONFIG_ISA_x86
55	  for (i = 0; i < ilen; i ++) {
56	#else
57	  for (i = ilen - 1; i >= 0; i --) {
58	#endif
59	    p += snprintf(p, 4, " %02x", inst[i]);
60	  }
61	  int ilen_max = MUXDEF(CONFIG_ISA_x86, 8, 4);
62	  int space_len = ilen_max - ilen;
63	  if (space_len < 0) space_len = 0;
64	  space_len = space_len * 3 + 1;
65	  memset(p, ' ', space_len);
66	  p += space_len;
67	
68	  void disassemble(char *str, int size, uint64_t pc, uint8_t *code, int nbyte);
69	  disassemble(p, s->logbuf + sizeof(s->logbuf) - p,
70	      MUXDEF(CONFIG_ISA_x86, s->snpc, s->pc), (uint8_t *)&s->isa.inst, ilen);
71	#endif
72	}
